		t.Fatal(err)
	}
	r.writeFile("operator.txt", "operator staged content\n")
	r.runGit("add", "operator.txt")

	workerSHA := r.commitOn(r.baseSHA, "feature.txt", "feature\n", "feat: feature")
	req := LandRequest{
		WorktreeDir:  r.dir,
